const SPEED    = 200.0
const JUMP_VEL = -400.0
const GRAVITY  = 980.0

func _physics_process(delta: float) -> void:
    if not is_on_floor():
        velocity.y += GRAVITY * delta

    if Input.is_action_just_pressed("ui_accept") and is_on_floor():
        velocity.y = JUMP_VEL

    var dir = Input.get_axis("ui_left", "ui_right")
    velocity.x = dir * SPEED

    move_and_slide()

