extends CharacterBody2D

@onready var anim = $AnimatedSprite2D

func _physics_process(delta: float) -> void:
    # movement code here...
    move_and_slide()

    if not is_on_floor():
        anim.play("jump")
    elif velocity.x != 0:
        anim.play("walk")
        anim.flip_h = velocity.x < 0
    else:
        anim.play("idle")

func die() -> void:
    anim.play("die")
    anim.animation_finished.connect(_on_death_animation_done)

func _on_death_animation_done() -> void:
    queue_free()

func fade_in(node: CanvasItem) -> void:
    var tween = create_tween()
    tween.tween_property(node, "modulate:a", 1.0, 0.3)

func bounce_scale(node: Node2D) -> void:
    var tween = create_tween()
    tween.tween_property(node, "scale", Vector2(1.3, 1.3), 0.1)
    tween.tween_property(node, "scale", Vector2(1.0, 1.0), 0.15)\
         .set_trans(Tween.TRANS_ELASTIC)

func slide_in_menu(panel: Control) -> void:
    panel.position.x = -panel.size.x
    var tween = create_tween()
    tween.tween_property(panel, "position:x", 0.0, 0.4)\
         .set_ease(Tween.EASE_OUT)\
         .set_trans(Tween.TRANS_QUART)

